const https = require('https');

const NOTION_TOKEN = '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';
const NOTION_VERSION = '2022-06-28';
const LICENZE_DB = '14fcf500-0a9e-4e5d-92f8-6ae6e4c2a4cc';

function notionReq(method, path, payload) {
  return new Promise((resolve, reject) => {
    const data = payload ? JSON.stringify(payload) : null;
    const opts = {
      hostname: 'api.notion.com',
      path: '/v1' + path,
      method,
      headers: {
        'Authorization': 'Bearer ' + NOTION_TOKEN,
        'Notion-Version': NOTION_VERSION,
        'Content-Type': 'application/json'
      }
    };
    if (data) opts.headers['Content-Length'] = Buffer.byteLength(data);
    const req = https.request(opts, (res) => {
      let body = '';
      res.on('data', c => body += c);
      res.on('end', () => {
        try {
          const p = JSON.parse(body);
          if (res.statusCode >= 400) {
            reject(new Error('Notion ' + res.statusCode + ': ' + (p.message || JSON.stringify(p).substring(0, 300))));
          } else {
            resolve(p);
          }
        } catch {
          reject(new Error('Bad JSON from Notion: ' + body.substring(0, 200)));
        }
      });
    });
    req.on('error', reject);
    req.setTimeout(15000, () => { req.destroy(); reject(new Error('Timeout 15s')); });
    if (data) req.write(data);
    req.end();
  });
}

function getText(p) {
  if (!p) return '';
  if (p.type === 'title') return (p.title || []).map(t => t.plain_text).join('');
  if (p.type === 'rich_text') return (p.rich_text || []).map(t => t.plain_text).join('');
  if (p.type === 'email') return p.email || '';
  return '';
}
function getDate(p) { return p && p.date ? p.date.start : null; }
function getSelect(p) { return p ? (p.select ? p.select.name : (p.status ? p.status.name : null)) : null; }
function getNumber(p) { return p ? p.number : null; }
function getCheckbox(p) { return p ? (p.checkbox || false) : false; }

const mvpPattern = /^ELAB-[A-Z0-9]{4}-[A-Z0-9]{4}$/i;

// === STEP 1: Leggi input ===
let rawInput = null;
let body = null;
try {
  rawInput = $input.first().json;
  body = rawInput.body || rawInput;
} catch (e) {
  return [{ json: { valid: false, error: 'INPUT_ERROR: ' + e.message, rawKeys: Object.keys($input.first().json || {}) } }];
}

const action = body.action || 'unknown';
const code = body.code || '';
const sessionId = body.sessionId || body.deviceId || '';

// === DEBUG: mostra cosa abbiamo ricevuto ===
const debug = {
  receivedAction: action,
  receivedCode: code,
  receivedSessionId: sessionId,
  bodyKeys: Object.keys(body),
  rawInputKeys: Object.keys(rawInput),
  hasBody: rawInput.body !== undefined,
  dbId: LICENZE_DB
};

let result = { valid: false, error: 'Azione non riconosciuta' };

try {
  if (action === 'verify') {
    if (!code) {
      result = { valid: false, error: 'Codice licenza mancante', _debug: debug };
    } else if (!mvpPattern.test(code)) {
      result = { valid: false, error: 'Formato licenza non valido. Usa ELAB-XXXX-XXXX', _debug: debug };
    } else {
      // === STEP 2: Query Notion — SENZA catch silenzioso ===
      let queryError = null;
      let found = null;
      let queryResult = null;

      try {
        queryResult = await notionReq('POST', '/databases/' + LICENZE_DB + '/query', {
          filter: { property: 'Codice', rich_text: { equals: code } },
          page_size: 1
        });
        if (queryResult.results && queryResult.results.length > 0) {
          found = queryResult.results[0];
        }
      } catch (e) {
        queryError = e.message;
      }

      // === STEP 3: Se query fallita, ritorna errore VISIBILE ===
      if (queryError) {
        result = {
          valid: true,
          school: 'ELAB Makers',
          email: '',
          expiry: new Date(Date.now() + 365 * 24 * 60 * 60 * 1000).toISOString(),
          plan: 'base',
          maxUsers: 1,
          sessionId,
          mvp: true,
          _queryError: queryError,
          _debug: debug
        };
      } else if (!found) {
        // Codice non trovato nel DB — MVP fallback
        result = {
          valid: true,
          school: 'ELAB Makers',
          email: '',
          expiry: new Date(Date.now() + 365 * 24 * 60 * 60 * 1000).toISOString(),
          plan: 'base',
          maxUsers: 1,
          sessionId,
          mvp: true,
          _notFound: true,
          _queryResultCount: (queryResult.results || []).length,
          _debug: debug
        };
      } else {
        // === STEP 4: Licenza trovata nel DB ===
        const props = found.properties || {};
        const propKeys = Object.keys(props);
        const school = getText(props['Scuola']);
        const email = getText(props['Email']);
        const expiry = getDate(props['Scadenza']);
        const plan = getSelect(props['Piano']) || 'base';
        const maxUsers = getNumber(props['MaxUtenti']) || 1;
        const active = getCheckbox(props['Attivo']);
        const lockedDevice = getText(props['DeviceId']);

        if (expiry && new Date(expiry) < new Date()) {
          result = { valid: false, error: 'Licenza scaduta', _debug: debug };
        } else if (props['Attivo'] && !active) {
          result = { valid: false, error: 'Licenza disattivata', _debug: debug };
        } else if (lockedDevice && lockedDevice !== sessionId && lockedDevice !== '') {
          result = { valid: false, error: 'DEVICE_LOCKED', _debug: debug };
        } else {
          // Lock device se non ancora lockato
          if (!lockedDevice || lockedDevice === '') {
            try {
              await notionReq('PATCH', '/pages/' + found.id, {
                properties: { 'DeviceId': { rich_text: [{ text: { content: sessionId } }] } }
              });
            } catch (lockErr) {
              // Non bloccare per errore di lock
            }
          }
          result = {
            valid: true,
            school,
            email,
            expiry: expiry || new Date(Date.now() + 365 * 24 * 60 * 60 * 1000).toISOString(),
            plan,
            maxUsers,
            sessionId,
            _foundPageId: found.id,
            _propKeys: propKeys,
            _debug: debug
          };
        }
      }
    }
  } else if (action === 'release') {
    let releaseError = null;
    try {
      const d = await notionReq('POST', '/databases/' + LICENZE_DB + '/query', {
        filter: { property: 'Codice', rich_text: { equals: code } },
        page_size: 1
      });
      if (d.results && d.results.length > 0) {
        const page = d.results[0];
        await notionReq('PATCH', '/pages/' + page.id, {
          properties: { 'DeviceId': { rich_text: [{ text: { content: '' } }] } }
        });
      }
    } catch (e) {
      releaseError = e.message;
    }
    result = { released: true, _releaseError: releaseError, _debug: debug };
  } else {
    result = { valid: false, error: 'Azione non riconosciuta: ' + action, _debug: debug };
  }
} catch (error) {
  result = {
    valid: false,
    error: 'UNCAUGHT: ' + error.message,
    _stack: error.stack ? error.stack.substring(0, 500) : null,
    _debug: debug
  };
}

return [{ json: result }];
